const userMessage = $input.first().json.chatInput;
const sessionId = $input.first().json.sessionId || 'default';
const debug = {};
const supaHeaders = {
  'Content-Type': 'application/json',
  'apikey': SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
};

// STEP 0: Checar cache de exemplos pra essa sessao
let searchResults = [];
let cached = false;
try {
  const cacheResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/rpc/get_prompt_cache`,
    headers: supaHeaders,
    body: { p_session_id: sessionId }
  });
  if (cacheResponse && Array.isArray(cacheResponse) && cacheResponse.length > 0) {
    searchResults = cacheResponse;
    cached = true;
    debug.cache = `HIT (${searchResults.length} exemplos)`;
  } else if (cacheResponse && !Array.isArray(cacheResponse) && cacheResponse !== null) {
    searchResults = cacheResponse;
    cached = true;
    debug.cache = `HIT (cache found)`;
  }
} catch (err) {
  debug.cache = `MISS`;
}

if (!cached) {
  // STEP 1: Gerar embedding
  let embedding = null;
  try {
    const embedResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/functions/v1/conversation-embed`,
      headers: { 'Content-Type': 'application/json' },
      body: { action: 'embed_query', text: userMessage }
    });
    embedding = embedResponse.embedding;
    debug.step1_embedding = embedding ? `OK (${embedding.length} dims)` : `FAIL`;
  } catch (err) {
    debug.step1_embedding = `ERROR: ${err.message}`;
  }

  // STEP 2: Buscar conversas similares
  if (embedding) {
    try {
      const embeddingStr = `[${embedding.join(',')}]`;
      const searchResponse = await this.helpers.httpRequest({
        method: 'POST',
        url: `${SUPABASE_URL}/rest/v1/rpc/buscar_conversas_similares`,
        headers: supaHeaders,
        body: {
          query_embedding: embeddingStr,
          nota_minima: 7,
          limite: 3
        }
      });
      searchResults = searchResponse || [];
      debug.step2_search = `OK (${searchResults.length} results)`;
      if (searchResults.length > 0) {
        debug.step2_first_result = { id: searchResults[0].id, nota: searchResults[0].nota, sim: searchResults[0].similaridade };
        // Similaridade boa? Cacheia pra essa sessao
        if (searchResults[0].similaridade > 0.5) {
          try {
            await this.helpers.httpRequest({
              method: 'POST',
              url: `${SUPABASE_URL}/rest/v1/rpc/set_prompt_cache`,
              headers: supaHeaders,
              body: { p_session_id: sessionId, p_exemplos: searchResults }
            });
            debug.cache = 'SAVED';
          } catch (e) {
            debug.cache = `SAVE_ERROR: ${e.message}`;
          }
        } else {
          debug.cache = `MISS (sim=${searchResults[0].similaridade.toFixed(3)}, threshold=0.5)`;
        }
      }
    } catch (err) {
      debug.step2_search = `ERROR: ${err.message}`;
    }
  } else {
    debug.step2_search = 'SKIPPED - no embedding';
  }
}

// STEP 3: Formatar exemplos dinamicos
let exemplosText = '(Nenhum exemplo encontrado para essa situacao — use os principios acima como guia.)';
let exemplosCount = 0;

if (searchResults.length > 0) {
  exemplosCount = searchResults.length;
  exemplosText = searchResults.map((ex, i) => {
    const msgs = ex.mensagens.map(m => `Cliente: ${m.user}\nTARS: ${m.bot}`).join('\n\n');
    return `### Exemplo ${i + 1} — ${ex.classificacao} (nota ${ex.nota}/10)\n**Contexto:** ${ex.resumo}\n\n${msgs}`;
  }).join('\n\n---\n\n');
}

